const text = $json.output?.[0]?.content?.[0]?.text ?? "";

const cleaned = text
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  parsed = {
    ai_category: "general_question",
    ai_urgency: "medium",
    ai_sentiment: "neutral",
    recommended_queue: "tier1_support",
    escalation_flag: false,
    confidence_score: 0.25,
    triage_reason: "Fallback applied because AI returned invalid JSON",
    fallback_applied: true
  };
}

return {
  json: {
    ...$json,
    ...parsed
  }
};

const urgency = $json.ai_urgency;
const isEnterprise = $json.customer_tier === "enterprise";
const escalation = $json.escalation_flag === true;

// VIP flag
const vip_flag = isEnterprise;

// SLA risk calculation
let sla_risk = "low";

if (urgency === "critical" || escalation) {
  sla_risk = "high";
} else if (urgency === "high") {
  sla_risk = "medium";
}

// Priority scoring
let priority_score = 30;

if (urgency === "critical") {
  priority_score = 100;
} else if (escalation) {
  priority_score = 90;
} else if (urgency === "high") {
  priority_score = 80;
} else if (urgency === "medium") {
  priority_score = 60;
}

// Enterprise customers get a boost
if (vip_flag) {
  priority_score += 10;
}

if (priority_score > 100) {
  priority_score = 100;
}

return {
  json: {
    ...$json,
    vip_flag,
    sla_risk,
    priority_score
  }
};

return items.map(item => {
  const tierMap = {
    enterprise: 'Enterprise',
    pro: 'Mid-Market',
    basic: 'SMB'
  };

  const clvMap = {
    enterprise: 85000,
    pro: 45000,
    basic: 5000
  };

  const sourceChannel = item.json.source_channel || '';
  const currentPriority = item.json.current_priority || '';
  const customerTier = (item.json.customer_tier || 'basic').toLowerCase();

  item.json.ticket_age_hours = Math.floor(Math.random() * 72) + 1;
  item.json.previous_reopens = Math.floor(Math.random() * 4);
  item.json.account_tier = tierMap[customerTier] || 'SMB';
  item.json.customer_lifetime_value = clvMap[customerTier] || 5000;

  if (sourceChannel === 'email') {
    item.json.ticket_age_hours += 12;
  }

  if (currentPriority === 'high') {
    item.json.previous_reopens = Math.max(item.json.previous_reopens, 1);
  }

  return item;
});

values.content:
=You are analyzing customer support tickets to detect escalation risk.

Evaluate the ticket using tone, urgency, and context.

Return ONLY valid JSON in this format:

{
  "sentiment": "positive | neutral | frustrated | angry",
  "frustration_score": number,
  "escalation_risk": "low | medium | high",
  "signals": ["signal1", "signal2"]
}

Rules:
- frustration_score must be between 1 and 10
- escalation_risk must be low, medium, or high
- signals should list reasons the ticket might escalate
- return JSON only, no extra text

Ticket Subject:
{{$json.subject}}

Ticket Description:
{{$json.description}}

Ticket Priority:
{{$json.current_priority}}

Previous Reopens:
{{$json.previous_reopens}}

Ticket Age (hours):
{{$json.ticket_age_hours}}

Account Tier:
{{$json.account_tier}}

