return items.map(item => {
  const raw =
    item.json.output?.[0]?.content?.[0]?.text ||
    item.json.output?.[0]?.text ||
    '';

  const cleaned = raw
    .replace(/```json\s*/i, '')
    .replace(/```/g, '')
    .trim();

  let parsed;

  try {
    parsed = JSON.parse(cleaned);
  } catch (error) {
    parsed = {
      sentiment: 'neutral',
      frustration_score: 5,
      escalation_risk: 'medium',
      signals: ['parse_fallback_applied']
    };
  }

  item.json.escalation_sentiment = parsed.sentiment || 'neutral';
  item.json.frustration_score = parsed.frustration_score ?? 5;
  item.json.escalation_risk = parsed.escalation_risk || 'medium';
  item.json.escalation_signals = parsed.signals || ['unknown'];

  return item;
});

return items.map(item => {

  let score = 0;

  const frustration = item.json.frustration_score || 5;
  const reopens = item.json.previous_reopens || 0;
  const age = item.json.ticket_age_hours || 0;
  const tier = item.json.account_tier || 'SMB';
  const priority = item.json.current_priority || 'normal';
  const aiRisk = item.json.escalation_risk || 'medium';

  score += frustration;
  score += reopens * 2;

  if (age > 48) score += 3;
  else if (age > 24) score += 2;

  if (tier === 'Enterprise') score += 3;
  else if (tier === 'Mid-Market') score += 1;

  if (priority === 'high') score += 2;

  if (aiRisk === 'high') score += 3;
  else if (aiRisk === 'medium') score += 1;

  let level = 'low';

if (score >= 11) level = 'critical';
else if (score >= 8) level = 'high';
else if (score >= 5) level = 'medium';

  item.json.escalation_score = score;
  item.json.escalation_level = level;

  const signals = item.json.escalation_signals || [];
  item.json.escalation_reason = signals.join(', ');

  return item;

});

return items.map(item => {

  const ticket = item.json.ticket_id || "Unknown";
  const customer = item.json.customer_name || "Unknown";
  const tier = item.json.account_tier || "Unknown";
  const level = item.json.escalation_level || "low";
  const score = item.json.escalation_score || 0;
  const reason = item.json.escalation_reason || "No signals detected";

  item.json.escalation_alert_message =
`🚨 Escalation Risk Detected

Ticket: ${ticket}
Customer: ${customer} (${tier})

Risk Level: ${level.toUpperCase()}
Score: ${score}

Signals:
${reason}`;

  return item;

});

return items.map(item => {
  item.json.recommended_queue = item.json.route_queue || 'tier1_support';
  return item;
});

return items.map(item => {
  item.json.route_queue = item.json.recommended_queue || '';
  item.json.route_category = item.json.ai_category || '';
  item.json.route_urgency = item.json.ai_urgency || '';
  return item;
});

const savedItems = $items("Persist Routing Fields", 0) || [];

return items.map((item, index) => {
  const source = savedItems[index] ? savedItems[index].json : {};

  item.json.route_queue = source.route_queue || '';
  item.json.route_category = source.route_category || '';
  item.json.route_urgency = source.route_urgency || '';

  return item;
});

return items.map(item => {
  item.json.escalation_score_number = Number(item.json.escalation_score || 0);
  return item;
});
